<?php require_once 'common.php'; topx('Stok'); echo '<div class="panel"><a class="btn dark" href="product_new.php">+ Yeni Ürün</a> <a class="btn" href="report.php?modul=stok" style="background:#334155;color:#fff">📊 Rapor</a></div>'; try{$rows=db()->query("SELECT id,name,quantity,unit,sale_price,critical_level FROM stock_items ORDER BY name LIMIT 200")->fetchAll();foreach($rows as $r){$kr=($r['quantity']<=($r['critical_level']??0));echo '<a class="item" href="product_view.php?id='.(int)$r['id'].'"><b>'.htmlspecialchars($r['name']).'</b>'.($kr?' <span style="color:#f87171;font-size:12px;font-weight:900">⚠️ kritik</span>':'').'<br><small>Stok: '.htmlspecialchars($r['quantity'].' '.$r['unit']).' · Satış: '.mm($r['sale_price']??0).'</small></a>';}}catch(Throwable $e){echo '<div class="err">'.htmlspecialchars($e->getMessage()).'</div>';} botx(); ?>